import pandas as pd
import numpy as np

# Define carrier plans
carriers = {
    'Run': {'monthly': 60, 'minutes': 400, 'texts': float('inf'), 'data': 1250, 'min_rate': 0.10, 'text_rate': 0, 'data_pack': 10, 'data_mb': 50},
    'Swim': {'monthly': 80, 'minutes': 180, 'texts': 1200, 'data': float('inf'), 'min_rate': 0.69, 'text_rate': 0.04, 'data_pack': 0, 'data_mb': 0},
    'Bike': {'monthly': 80, 'minutes': float('inf'), 'texts': 750, 'data': 2000, 'min_rate': 0, 'text_rate': 0.10, 'data_pack': 35, 'data_mb': 100},
    'Jump': {'monthly': 75, 'minutes': float('inf'), 'texts': 500, 'data': 1500, 'min_rate': 0.99, 'text_rate': 0.05, 'data_pack': 20, 'data_mb': 200},
    'Kayak': {'monthly': 60, 'minutes': 320, 'texts': float('inf'), 'data': 3000, 'min_rate': 0.59, 'text_rate': 0, 'data_pack': 50, 'data_mb': 50},
    'Skip': {'monthly': 10, 'minutes': 150, 'texts': 3000, 'data': 1250, 'min_rate': 0.59, 'text_rate': 0.06, 'data_pack': 45, 'data_mb': 300}
}

# Calculate usage for 36 months
base_usage = {'minutes': 300, 'texts': 1000, 'data': 2000}
monthly_costs = {}

for carrier, plan in carriers.items():
    total_cost = 0
    for month in range(36):
        year = month // 12
        month_in_year = (month % 12) + 1

        # Apply growth
        growth = 1.05 ** year
        usage = {k: v * growth for k, v in base_usage.items()}

        # Apply seasonal multipliers
        if month_in_year in [6, 7]: # June, July
            usage = {k: v * 1.5 for k, v in usage.items()}
        elif month_in_year == 12: # December
            usage = {k: v * 2 for k, v in usage.items()}

        monthly_cost = plan['monthly']

        # Calculate overages
        if usage['minutes'] > plan['minutes'] and plan['minutes'] != float('inf'):
            monthly_cost += (usage['minutes'] - plan['minutes']) * plan['min_rate']

        if usage['texts'] > plan['texts'] and plan['texts'] != float('inf'):
            monthly_cost += (usage['texts'] - plan['texts']) * plan['text_rate']

        if usage['data'] > plan['data'] and plan['data'] != float('inf'):
            data_packs = np.ceil((usage['data'] - plan['data']) / plan['data_mb'])
            monthly_cost += data_packs * plan['data_pack']

        total_cost += monthly_cost

    monthly_costs[carrier] = total_cost

print("Total costs without incentives:")
for carrier, cost in monthly_costs.items():
    print(f"{carrier}: ${cost:.2f}")

import plotly.graph_objects as go
from plotly.subplots import make_subplots

# Calculate costs with incentives
incentive_costs = {}
savings = {}

for carrier, plan in carriers.items():
    total_cost = 0
    for month in range(36):
        year = month // 12
        month_in_year = (month % 12) + 1

        growth = 1.05 ** year
        usage = {k: v * growth for k, v in base_usage.items()}

        if month_in_year in [6, 7]:
            usage = {k: v * 1.5 for k, v in usage.items()}
        elif month_in_year == 12:
            usage = {k: v * 2 for k, v in usage.items()}

        monthly_cost = plan['monthly']

        # Apply incentives
        if carrier == 'Run' and month < 2:
            monthly_cost = 0
        elif carrier == 'Swim' and month < 6:
            monthly_cost *= 0.5
        elif carrier == 'Bike' and month < 3:
            # Calculate full cost first, then apply 60% discount
            full_cost = monthly_cost
            if usage['minutes'] > plan['minutes'] and plan['minutes'] != float('inf'):
                full_cost += (usage['minutes'] - plan['minutes']) * plan['min_rate']
            if usage['texts'] > plan['texts'] and plan['texts'] != float('inf'):
                full_cost += (usage['texts'] - plan['texts']) * plan['text_rate']
            if usage['data'] > plan['data'] and plan['data'] != float('inf'):
                data_packs = np.ceil((usage['data'] - plan['data']) / plan['data_mb'])
                full_cost += data_packs * plan['data_pack']
            total_cost += full_cost * 0.4
            continue

        # Calculate overages (except for Bike during incentive period)
        if usage['minutes'] > plan['minutes'] and plan['minutes'] != float('inf'):
            monthly_cost += (usage['minutes'] - plan['minutes']) * plan['min_rate']

        if usage['texts'] > plan['texts'] and plan['texts'] != float('inf'):
            monthly_cost += (usage['texts'] - plan['texts']) * plan['text_rate']

        # Adjust data allowance for Jump and Skip incentives
        data_allowance = plan['data']
        if carrier == 'Jump' and month < 9:
            data_allowance += 1000
        elif carrier == 'Skip' and month < 3:
            data_allowance *= 2

        if usage['data'] > data_allowance and data_allowance != float('inf'):
            data_packs = np.ceil((usage['data'] - data_allowance) / plan['data_mb'])
            monthly_cost += data_packs * plan['data_pack']

        total_cost += monthly_cost

    incentive_costs[carrier] = total_cost
    savings[carrier] = monthly_costs[carrier] - total_cost

# Find carrier with least savings
least_savings_carrier = min(savings, key=savings.get)

print("\nSavings from incentives:")
for carrier, saving in savings.items():
    print(f"{carrier}: ${saving:.2f}")
print(f"\nCarrier with least savings: {least_savings_carrier} (${savings[least_savings_carrier]:.2f})")

# Visualization
fig = make_subplots(rows=1, cols=2, subplot_titles=['Cost Comparison', 'Savings by Carrier'])

carriers_list = list(carriers.keys())
no_incentive = [monthly_costs[c] for c in carriers_list]
with_incentive = [incentive_costs[c] for c in carriers_list]
savings_list = [savings[c] for c in carriers_list]

fig.add_trace(go.Bar(name='No Incentive', x=carriers_list, y=no_incentive), row=1, col=1)
fig.add_trace(go.Bar(name='With Incentive', x=carriers_list, y=with_incentive), row=1, col=1)
fig.add_trace(go.Bar(x=carriers_list, y=savings_list, marker_color='green'), row=1, col=2)

fig.update_xaxes(title_text='Carriers', row=1, col=1)
fig.update_yaxes(title_text='Total Cost ($)', row=1, col=1)
fig.update_xaxes(title_text='Carriers', row=1, col=2)
fig.update_yaxes(title_text='Savings ($)', row=1, col=2)

fig.update_layout(title='Mobile Plan Cost Analysis Over 36 Months')
fig.show()
